(15, 'albertpipo13@gmail.com', 'Albert Pipo', 'Re: Virtual Office Subscription Renewal Notice', '<div dir=\"ltr\">test</div><br><div class=\"gmail_quote gmail_quote_container\"><div dir=\"ltr\" class=\"gmail_attr\">On Fri, Mar 20, 2026 at 2:00 PM Launchpad Virtual Office &lt;<a href=\"mailto:admin@launchpadcoworkingph.com\">admin@launchpadcoworkingph.com</a>&gt; wrote:<br></div><blockquote class=\"gmail_quote\" style=\"margin:0px 0px 0px 0.8ex;border-left:1px solid rgb(204,204,204);padding-left:1ex\">\n    <div style=\"font-family:Arial,sans-serif;max-width:600px;margin:0px auto;border:1px solid rgb(238,238,238);border-radius:8px;overflow:hidden\">\n      <div style=\"background-color:rgb(254,252,232);text-align:center;padding:20px;border-bottom:3px solid rgb(210,243,76)\">\n        <img src=\"http:///src/assets/launchpad-logo.png\" alt=\"Launchpad Business Logo\" style=\"max-width: 250px;\">\n      </div>\n      <div style=\"padding:30px;color:rgb(51,51,51);line-height:1.6\">\n        <h2>Greetings, [Client Name]!</h2>\n        <p>We hope this email finds you well.</p>\n        <p>This is a formal notification regarding your <strong>Virtual Office</strong> subscription for <strong>[Company Name]</strong>. Our records indicate that your current subscription is scheduled to expire in <strong style=\"color:rgb(234,179,8);font-size:1.1em\">[X] days</strong> (on <strong>[Exact Expiry Date]</strong>).</p>\n        <p>To continue accessing the services and features of your Virtual Office, please renew your subscription at your earliest convenience. Maintaining an active subscription is vital for the continuity of your business operations.</p>\n        <p>Thank you for choosing Launchpad as your business partner.</p>\n        <br>\n        <p>Best Regards,<br><strong>Launchpad Management Team</strong></p>\n      </div>\n    </div>\n  \n</blockquote></div>\n', '<CAHfB177QSmTCs2e+WFR4uQ2iF5AkRJgfYuHUH+96brj4i6R4Og@mail.gmail.com>', NULL, '2026-03-20 06:26:25', '2026-03-20 15:24:39'),
