(21, 'enrique_manas@yahoo.com', 'enrique manas', 'Muntinlupa 2026 Permit', '<html><head></head><body><div class=\"yahoo-style-wrap\" style=\"font-family:times new roman, new york, times, serif;font-size:13px;\"><div dir=\"ltr\" data-setdir=\"false\">Hello,</div><div dir=\"ltr\" data-setdir=\"false\"><br></div><div dir=\"ltr\" data-setdir=\"false\">I am attaching 2026 Muntinlupa Permit as per request.</div><div dir=\"ltr\" data-setdir=\"false\">Let me know if you have questions.</div><div dir=\"ltr\" data-setdir=\"false\"><br></div><div dir=\"ltr\" data-setdir=\"false\">Thank you.</div><div dir=\"ltr\" data-setdir=\"false\"><br></div><div dir=\"ltr\" data-setdir=\"false\">Henry Manas</div><div dir=\"ltr\" data-setdir=\"false\">Rampiere IT Solutions</div></div></body></html>', '<1999999959.55570.1774493491281@mail.yahoo.com>', '[{\"filename\":\"Muntinlupa_2026_Rampiere.jpg\",\"url\":\"https://drive.google.com/file/d/1SQ4FJ4lGPZ_rAW5tXYhqL3RDf1nZDluS/view?usp=drivesdk\",\"type\":\"image/jpeg\"}]', '2026-03-26 02:52:11', NULL),
(22, 'Ross.Malonda@qbe.com', 'Ross Mark Malonda', 'Recall: Oil Shortage - Query - OG', '<p>Ross Mark Malonda would like to recall the message, &quot;Oil Shortage - Query - OG&quot;.<br/>------------------ IMPORTANT NOTICE : The information in this email is confidential and may also be privileged. If you are not the intended recipient, any use or dissemination of the information and any disclosure or copying of this email is unauthorised and strictly prohibited. If you have received this email in error, please promptly inform us by reply email or telephone. You should also delete this email and destroy any hard copies produced.</p>', '<CY4PR0201MB3571AAA9964DDB1F2E46AD059456A@CY4PR0201MB3571.namprd02.prod.outlook.com>', NULL, '2026-03-26 02:58:55', NULL);
