(24, 'admin@griffinstone.com.ph', 'Admin Griffinstone', 'Re: FOR PICK UP: Request Access Card 2026_Shirefolk', '<div dir=\"ltr\"><div><span style=\"color:rgb(80,0,80)\"><span style=\"color:inherit\"><span style=\"color:inherit\"><span style=\"color:inherit\"><div><div dir=\"ltr\" style=\"font-family:&quot;Helvetica Neue&quot;,Helvetica,Arial,sans-serif\"><b style=\"color:rgb(0,0,0)\">Hi. Maam Kath</b><span style=\"color:rgb(0,0,0)\">, </span></div></div><div dir=\"ltr\" style=\"font-family:&quot;Helvetica Neue&quot;,Helvetica,Arial,sans-serif\"><span style=\"color:rgb(0,0,0)\"><br></span></div><div style=\"font-family:&quot;Helvetica Neue&quot;,Helvetica,Arial,sans-serif\"><span style=\"color:rgb(0,0,0)\">Good day. </span></div></span></span></span><span style=\"color:inherit\"><div><br></div><div><font color=\"#000000\">Please be informed the requested new access card is now available at the lobby reception.</font></div></span></span><div style=\"color:rgb(80,0,80)\"><font color=\"#000000\">Kindly arrange for your representative to collect it .</font></div></div><div style=\"color:rgb(80,0,80)\"><font color=\"#000000\"><br></font></div><div style=\"color:rgb(80,0,80)\"><img src=\"data:image/png;base64,\" alt=\"image.png\" style=\"margin-right: 0px;\"><br></div><div style=\"color:rgb(80,0,80)\"><br></div><div style=\"color:rgb(80,0,80)\"><br></div><div style=\"\"><font color=\"#000000\">Thank you. </font></div><div><div dir=\"ltr\" class=\"gmail_signature\" data-smartmail=\"gmail_signature\"><div dir=\"ltr\"><div style=\"color:rgb(34,34,34)\"><br></div><div style=\"color:rgb(34,34,34)\"><div><br></div></div><p class=\"MsoNormal\" style=\"margin-bottom:0.0001pt;color:rgb(80,0,80);background-image:initial;background-position:initial;background-repeat:initial;line-height:normal\"><span style=\"font-size:12pt;line-height:17.12px;font-family:Arial,sans-serif;color:black\">Best Regards,</span><span style=\"font-family:Arial,sans-serif\"><br></span><span style=\"font-famil