(34, 'Ross.Malonda@qbe.com', 'Ross Mark Malonda', 'RE: Request Access to Large Room 2 - Aircon Repair', '<html xmlns:v=\"urn:schemas-microsoft-com:vml\" xmlns:o=\"urn:schemas-microsoft-com:office:office\" xmlns:w=\"urn:schemas-microsoft-com:office:word\" xmlns:m=\"http://schemas.microsoft.com/office/2004/12/omml\" xmlns=\"http://www.w3.org/TR/REC-html40\">\n<head>\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=iso-8859-1\">\n<meta name=\"Generator\" content=\"Microsoft Word 15 (filtered medium)\">\n<!--[if !mso]><style>v\\:* {behavior:url(#default#VML);}\no\\:* {behavior:url(#default#VML);}\nw\\:* {behavior:url(#default#VML);}\n.shape {behavior:url(#default#VML);}\n</style><![endif]--><style><!--\n/* Font Definitions */\n@font-face\n	{font-family:\"Cambria Math\";\n	panose-1:2 4 5 3 5 4 6 3 2 4;}\n@font-face\n	{font-family:Calibri;\n	panose-1:2 15 5 2 2 2 4 3 2 4;}\n@font-face\n	{font-family:Aptos;}\n@font-face\n	{font-family:\"QBE Sans\";\n	panose-1:2 11 5 3 2 2 3 2 2 4;}\n@font-face\n	{font-family:\"QBE Sans Medium\";\n	panose-1:2 11 6 3 2 2 3 2 2 4;}\n/* Style Definitions */\np.MsoNormal, li.MsoNormal, div.MsoNormal\n	{margin:0cm;\n	font-size:12.0pt;\n	font-family:\"Aptos\",sans-serif;}\na:link, span.MsoHyperlink\n	{mso-style-priority:99;\n	color:blue;\n	text-decoration:underline;}\nspan.EmailStyle19\n	{mso-style-type:personal-reply;\n	font-family:\"Aptos\",sans-serif;\n	color:windowtext;}\n.MsoChpDefault\n	{mso-style-type:export-only;\n	font-size:10.0pt;\n	mso-ligatures:none;}\n@page WordSection1\n	{size:612.0pt 792.0pt;\n	margin:72.0pt 72.0pt 72.0pt 72.0pt;}\ndiv.WordSection1\n	{page:WordSection1;}\n--></style><!--[if gte mso 9]><xml>\n<o:shapedefaults v:ext=\"edit\" spidmax=\"1026\" />\n</xml><![endif]--><!--[if gte mso 9]><xml>\n<o:shapelayout v:ext=\"edit\">\n<o:idmap v:ext=\"edit\" data=\"1\" />\n</o:shapelayout></xml><![endif]-->\n</head>\n<body lang=\"EN-PH\" link=\"blue\" vlink=\"purple\" style=\"word-wrap:break-word\">\n<div class=\"Wor